#!/usr/bin/env python3
from pathlib import Path
import json

ROOT = Path('/home/tiny4lurv/.openclaw/workspace')
SRC_DIRS = [
    ROOT / 'rag' / 'clean_md',
    ROOT / 'docs',
    ROOT / 'docs' / 'converted',
]
OUT = ROOT / 'rag' / 'index' / 'chunks.jsonl'


def chunk_text(text: str, size: int = 1400, overlap: int = 200):
    chunks = []
    i = 0
    n = len(text)
    while i < n:
        j = min(i + size, n)
        chunks.append(text[i:j])
        if j == n:
            break
        i = max(0, j - overlap)
    return chunks


def iter_files():
    for d in SRC_DIRS:
        if not d.exists():
            continue
        for p in sorted(d.rglob('*')):
            if p.is_file() and p.suffix.lower() in {'.md', '.txt'}:
                yield p


def main():
    OUT.parent.mkdir(parents=True, exist_ok=True)
    count = 0
    with OUT.open('w', encoding='utf-8') as f:
        for p in iter_files():
            text = p.read_text(encoding='utf-8', errors='ignore').strip()
            if not text:
                continue
            rel = str(p.relative_to(ROOT))
            source_type = 'website' if rel.startswith('rag/clean_md') or rel.startswith('rag/clean_txt') else 'docs'
            for idx, ch in enumerate(chunk_text(text)):
                rec = {
                    'id': f'{rel}::chunk::{idx}',
                    'path': rel,
                    'source_type': source_type,
                    'chunk_index': idx,
                    'text': ch,
                }
                f.write(json.dumps(rec, ensure_ascii=False) + '\n')
                count += 1
    print(count)


if __name__ == '__main__':
    main()

